import{_ as i,c as a,o as n,ae as l}from"./chunks/framework.B7Y1jjX-.js";const E=JSON.parse('{"title":"浏览器工作原理","description":"","frontmatter":{},"headers":[],"relativePath":"notes/前端/浏览器与环境/浏览器工作原理.md","filePath":"notes/前端/浏览器与环境/浏览器工作原理.md"}'),t={name:"notes/前端/浏览器与环境/浏览器工作原理.md"};function r(e,s,p,h,o,g){return n(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="浏览器工作原理" tabindex="-1">浏览器工作原理 <a class="header-anchor" href="#浏览器工作原理" aria-label="Permalink to &quot;浏览器工作原理&quot;">​</a></h1><h2 id="_1-进程架构" tabindex="-1">1 进程架构 <a class="header-anchor" href="#_1-进程架构" aria-label="Permalink to &quot;1 进程架构&quot;">​</a></h2><p>现代浏览器采用多进程架构，主要包含以下核心进程：</p><ul><li><strong>浏览器主进程 (Browser Process)</strong>：负责界面显示、用户交互、子进程管理</li><li><strong>渲染进程 (Renderer Process)</strong>：位于沙盒之中，负责页面渲染、脚本执行（每个==标签页==都是独立的进程）： <ul><li>渲染主线程</li><li>合成线程</li><li>栅格线程等</li></ul></li><li><strong>GPU进程 (GPU Process)</strong>：负责图形渲染、3D绘制等GPU相关任务</li><li><strong>网络进程 (Network Process)</strong>：负责所有网络资源请求和管理 ![[Pasted image 20251125142805.png]]</li></ul><p>![[Pasted image 20250903155953.png]]</p><p>多进程架构的优势包括：</p><ul><li>隔离性：单个标签页崩溃不影响其他页面</li><li>安全性：渲染进程在沙盒中与操作系统隔离开来</li><li>性能优化</li></ul><h2 id="_2渲染原理" tabindex="-1">2渲染原理 <a class="header-anchor" href="#_2渲染原理" aria-label="Permalink to &quot;2渲染原理&quot;">​</a></h2><p>渲染进程在==文档加载==、样式==变化==、用户==交互==时触发</p><h3 id="从输入地址到渲染出页面的过程" tabindex="-1">从输入地址到渲染出页面的过程 <a class="header-anchor" href="#从输入地址到渲染出页面的过程" aria-label="Permalink to &quot;从输入地址到渲染出页面的过程&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[用户输入URL] --&gt; B[浏览器主进程]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[网络进程]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[DNS解析]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[建立TCP连接]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[发送HTTP请求]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[接收HTML响应]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[渲染进程接收数据]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I[HTML解析/DOM构建]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[遇到JavaScript/暂停解析]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; K[执行JavaScript]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; I</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; L[CSS解析/CSSOM构建]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; M[渲染树构建]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M --&gt; N[布局Layout/重排]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N --&gt; O[分层Layer]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; P[绘制Painting/重绘]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; Q[合成Compositing]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q --&gt; R[GPU进程处理]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; S[屏幕显示]</span></span></code></pre></div><h3 id="网络请求部分" tabindex="-1">网络请求部分 <a class="header-anchor" href="#网络请求部分" aria-label="Permalink to &quot;网络请求部分&quot;">​</a></h3><ol><li><strong>DNS解析</strong>：将域名转换为IP地址</li><li><strong>TCP连接</strong>：与服务器建立可靠连接（三次握手）</li><li><strong>HTTP请求</strong>：发送请求头和数据</li><li><strong>响应处理</strong>：接收服务器返回的HTML、CSS、JS等资源</li><li><strong>数据传输</strong>：将响应数据传递给渲染进程进行解析</li><li><strong>预解析器</strong>：提前下载CSS和JavaScript资源</li></ol><h3 id="dom树与cssom树" tabindex="-1">DOM树与CSSOM树 <a class="header-anchor" href="#dom树与cssom树" aria-label="Permalink to &quot;DOM树与CSSOM树&quot;">​</a></h3><p>HTML解析：</p><ul><li><strong>令牌化 (Tokenization)</strong>：将HTML标签转换为令牌</li><li><strong>树构建</strong>：根据标签嵌套关系构建DOM树</li><li><strong>预解析优化</strong>：主解析器工作时，预解析器提前扫描和下载外部资源</li></ul><p>CSS解析与HTML解析并行进行 JavaScript对渲染流程的影响：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 同步脚本阻塞解析 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 异步脚本不阻塞 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> async</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 延迟执行脚本 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defer</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>阻塞机制：</p><ul><li><strong>解析阻塞</strong>：同步脚本会暂停HTML解析</li><li><strong>渲染阻塞</strong>：CSS和JavaScript都可能阻塞渲染，CSS不会阻塞HTML解析，但会阻塞页面渲染</li></ul><h3 id="渲染树" tabindex="-1">渲染树 <a class="header-anchor" href="#渲染树" aria-label="Permalink to &quot;渲染树&quot;">​</a></h3><p>结合DOM和CSSOM生成渲染树：</p><ul><li><strong>仅包含可见元素</strong>：<code>display: none</code>的元素不进入渲染树</li><li><strong>样式计算</strong>：为每个元素计算最终样式（层叠、继承）</li><li><strong>可见性处理</strong>：<code>visibility: hidden</code>的元素仍在渲染树中但不可见</li></ul><h3 id="布局layout-重排-流程" tabindex="-1">布局Layout（重排）流程 <a class="header-anchor" href="#布局layout-重排-流程" aria-label="Permalink to &quot;布局Layout（重排）流程&quot;">​</a></h3><ul><li><strong>布局计算</strong>：计算每个元素在视口中的精确位置和大小（重排）</li><li><strong>重排触发</strong>：当布局变化时需要重新计算元素几何属性</li></ul><ol><li><strong>计算位置大小</strong>：确定元素在视口中的确切位置和尺寸</li><li><strong>重排影响</strong>：布局变化会导致整个渲染流程重新执行</li></ol><h3 id="分层layer" tabindex="-1">分层Layer <a class="header-anchor" href="#分层layer" aria-label="Permalink to &quot;分层Layer&quot;">​</a></h3><p>浏览器将页面分解为多个图层进行优化渲染：</p><ul><li><strong>显式分层</strong>：<code>transform</code>, <code>opacity</code>, <code>will-change</code>等CSS属性</li><li><strong>隐式分层</strong>：重叠内容、视频、canvas等特殊元素</li><li><strong>硬件加速</strong>：使用GPU进行图层合成，提升性能</li><li><strong>层管理</strong>：浏览器自动管理图层创建和销毁</li></ul><h3 id="绘制paint-重绘" tabindex="-1">绘制Paint（重绘） <a class="header-anchor" href="#绘制paint-重绘" aria-label="Permalink to &quot;绘制Paint（重绘）&quot;">​</a></h3><p>将渲染树转换为屏幕像素的过程：</p><ol><li><strong>绘制列表生成</strong>：为每个图层生成绘制命令</li><li><strong>重绘触发</strong>：当元素外观变化但不影响布局时发生</li><li><strong>绘制优化</strong>：仅重新绘制受影响区域</li></ol><h3 id="光栅化raster" tabindex="-1">光栅化raster <a class="header-anchor" href="#光栅化raster" aria-label="Permalink to &quot;光栅化raster&quot;">​</a></h3><p>分块tiles：</p><ul><li><strong>图块划分</strong>：将大图层分割为小图块（通常256x256或512x512）</li><li><strong>视口优先</strong>：优先渲染可视区域内的图块</li><li><strong>渐进加载</strong>：离视口越远的图块优先级越低</li><li><strong>缓存机制</strong>：已光栅化的图块会被缓存复用</li></ul><p>光栅化：将矢量图形转换为位图</p><ol><li>合成器将图层分为图块</li><li>光栅线程将图块转换为位图</li><li>GPU进程合成最终图像</li></ol><h3 id="合成" tabindex="-1">合成 <a class="header-anchor" href="#合成" aria-label="Permalink to &quot;合成&quot;">​</a></h3><p>合成器线程将各个图层合成为最终图像frame：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[图层1] --&gt; D[合成器]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B[图层2] --&gt; D</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C[图层3] --&gt; D</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[帧缓冲区]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[屏幕显示]</span></span></code></pre></div><p>[合成优势]：</p><ul><li><strong>独立合成</strong>：图层变化无需重新布局和绘制</li><li><strong>GPU加速</strong>：利用显卡硬件能力提升性能</li><li><strong>60fps目标</strong>：每16.67ms完成一次完整的渲染流水线</li></ul><h3 id="绘制draw" tabindex="-1">绘制draw <a class="header-anchor" href="#绘制draw" aria-label="Permalink to &quot;绘制draw&quot;">​</a></h3><p>![[Pasted image 20250922222036.png]] [性能优化建议]：</p><ol><li><strong>减少重排reflow</strong>：批量DOM操作，使用文档片段，尽量减少节点的几何信息、DOM结构、宽高、字体大小的频繁修改</li><li><strong>优化重绘repaint</strong>：使用CSS类名切换而非直接样式修改</li><li><strong>利用合成层</strong>：对动画元素使用transform和opacity</li><li><strong>避免布局抖动</strong>：不要在循环中连续读取布局属性</li><li><strong>减少图层数量</strong>：避免不必要的图层创建，防止&quot;层爆炸&quot;</li></ol><h3 id="现代渲染引擎优化特性" tabindex="-1">现代渲染引擎优化特性 <a class="header-anchor" href="#现代渲染引擎优化特性" aria-label="Permalink to &quot;现代渲染引擎优化特性&quot;">​</a></h3><p>[补充说明]：现代浏览器还包含以下优化机制：</p><ul><li><strong>增量布局</strong>：只重新计算变化部分的布局</li><li><strong>懒加载</strong>：延迟加载视口外的图片和内容</li><li><strong>预渲染</strong>：预测用户行为提前渲染可能访问的页面</li><li><strong>缓存机制</strong>：复用已光栅化的图块和计算结果</li><li><strong>并行处理</strong>：多个渲染阶段可以并行执行提升效率</li></ul>`,48)])])}const d=i(t,[["render",r]]);export{E as __pageData,d as default};
